import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

/* ── Icons ────────────────────────────────────────────────────── */
const DashboardIcon = () => (
    <svg className="w-4.5 h-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <rect x="3" y="3" width="7" height="7" rx="1" />
        <rect x="14" y="3" width="7" height="7" rx="1" />
        <rect x="3" y="14" width="7" height="7" rx="1" />
        <rect x="14" y="14" width="7" height="7" rx="1" />
    </svg>
);
const MicIcon = () => (
    <svg className="w-4.5 h-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M19 10v2a7 7 0 0 1-14 0v-2M12 19v4M8 23h8" />
    </svg>
);
const BriefcaseIcon = () => (
    <svg className="w-4.5 h-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M20 7H4a2 2 0 00-2 2v10a2 2 0 002 2h16a2 2 0 002-2V9a2 2 0 00-2-2z" />
        <path strokeLinecap="round" strokeLinejoin="round" d="M16 7V6a2 2 0 00-2-2h-4a2 2 0 00-2 2v1" />
    </svg>
);
const GroupIcon = () => (
    <svg className="w-4.5 h-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z" />
    </svg>
);
const SparkleIcon = () => (
    <svg className="w-4.5 h-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M5 3l1.5 4.5L11 9l-4.5 1.5L5 15l-1.5-4.5L-1 9l4.5-1.5L5 3z" transform="translate(7 3)" />
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M3 3l.75 2.25L6 6l-2.25.75L3 9l-.75-2.25L0 6l2.25-.75L3 3z" transform="translate(13 13)" />
    </svg>
);
const BookIcon = () => (
    <svg className="w-4.5 h-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
    </svg>
);
const ZapIcon = () => (
    <svg className="w-4.5 h-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
    </svg>
);
const LogoutIcon = () => (
    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round"
            d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
    </svg>
);

const XP_LEVELS = [
    { min: 0, label: 'Beginner Speaker' },
    { min: 500, label: 'Developing Speaker' },
    { min: 1500, label: 'Confident Communicator' },
    { min: 3000, label: 'Interview Ready' },
    { min: 6000, label: 'Corporate Pro' },
];

function getXpLevelLabel(xp = 0) {
    for (let i = XP_LEVELS.length - 1; i >= 0; i--) {
        if (xp >= XP_LEVELS[i].min) return XP_LEVELS[i].label;
    }
    return XP_LEVELS[0].label;
}

const navItems = [
    { to: '/dashboard', icon: <DashboardIcon />, label: 'Dashboard', badge: null },
    { to: '/practice', icon: <MicIcon />, label: 'Practice', badge: 'Hot' },
    { to: '/interview', icon: <BriefcaseIcon />, label: 'Interview', badge: null },
    { to: '/gd', icon: <GroupIcon />, label: 'Group Discussion', badge: 'Live' },
    { to: '/learning', icon: <BookIcon />, label: 'Learning Hub', badge: 'New' },
    { to: '/challenges', icon: <ZapIcon />, label: 'Challenges', badge: '🔥' },
    { to: '/personality', icon: <SparkleIcon />, label: 'Personality', badge: null },
];

export default function Sidebar({ open, onClose }) {
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const initials = user?.name
        ? user.name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2)
        : 'U';

    const xpPercent = Math.min(((user?.xp || 0) % 1000) / 1000 * 100, 100);

    return (
        <>
            {/* Mobile overlay */}
            {open && (
                <div
                    className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm md:hidden"
                    onClick={onClose}
                />
            )}

            {/* Sidebar panel */}
            <aside
                className={`
          fixed top-0 left-0 z-50 h-full w-64 bg-dark-800 border-r border-white/5
          flex flex-col transition-transform duration-300
          md:translate-x-0 md:static md:z-auto
          ${open ? 'translate-x-0' : '-translate-x-full'}
        `}
            >
                {/* Logo */}
                <div className="flex items-center gap-3 px-5 h-16 border-b border-white/5 flex-shrink-0">
                    <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-primary-500 to-accent-500
                          flex items-center justify-center shadow-neon-blue flex-shrink-0">
                        <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24"
                            stroke="currentColor" strokeWidth={2}>
                            <path strokeLinecap="round" strokeLinejoin="round"
                                d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
                            <path strokeLinecap="round" strokeLinejoin="round"
                                d="M19 10v2a7 7 0 0 1-14 0v-2M12 19v4M8 23h8" />
                        </svg>
                    </div>
                    <div>
                        <p className="font-display font-bold text-white text-base leading-tight">UnMute</p>
                        <p className="text-white/30 text-[10px] leading-tight">Turn Your Voice On</p>
                    </div>
                </div>

                {/* Navigation */}
                <nav className="flex-1 overflow-y-auto px-3 py-4 space-y-1">
                    {navItems.map(item => (
                        <NavLink
                            key={item.to}
                            to={item.to}
                            onClick={() => onClose?.()}
                            className={({ isActive }) =>
                                isActive
                                    ? 'nav-link-active flex items-center gap-3 px-3 py-2.5 rounded-xl'
                                    : 'nav-link'
                            }
                        >
                            <span className="flex-shrink-0">{item.icon}</span>
                            <span className="flex-1">{item.label}</span>
                            {item.badge && (
                                <span className={`badge text-[10px] px-2 py-0.5 ${item.badge === 'Live'
                                    ? 'bg-neon-green/20 text-neon-green border border-neon-green/30'
                                    : 'bg-neon-pink/20 text-neon-pink border border-neon-pink/30'
                                    }`}>
                                    {item.badge === 'Live' && <span className="w-1.5 h-1.5 rounded-full bg-neon-green animate-pulse-slow mr-1 block" />}
                                    {item.badge}
                                </span>
                            )}
                        </NavLink>
                    ))}
                </nav>

                {/* User card */}
                <div className="flex-shrink-0 px-3 pb-4 space-y-2">
                    {/* XP Progress */}
                    <div className="glass-card px-4 py-3">
                        <div className="flex items-center justify-between mb-2">
                            <div>
                                <p className="text-white text-xs font-semibold">{user?.name || 'User'}</p>
                                <p className="text-white/40 text-[10px]">
                                    {getXpLevelLabel(user?.xp)} · Lv.{user?.level || 1}
                                </p>
                            </div>
                            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-primary-500 to-accent-500
                              flex items-center justify-center text-white text-xs font-bold">
                                {initials}
                            </div>
                        </div>
                        <div className="progress-bar">
                            <div className="progress-fill" style={{ width: `${xpPercent}%` }} />
                        </div>
                        <div className="flex justify-between mt-1">
                            <span className="text-white/30 text-[10px]">{user?.xp || 0} XP</span>
                            <span className="text-white/30 text-[10px]">
                                {1000 - ((user?.xp || 0) % 1000)} to next level
                            </span>
                        </div>
                    </div>

                    {/* Logout */}
                    <button
                        onClick={handleLogout}
                        className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-red-400/70
                       hover:text-red-400 hover:bg-red-500/10 transition-all duration-200 text-sm"
                    >
                        <LogoutIcon />
                        Sign Out
                    </button>
                </div>
            </aside>
        </>
    );
}
